module top_module (
    input [2:0] a,
    input en,
    output reg [7:0] y
);
  wire [2:0] _tap_a = a & {3{1'b1}};


    always @(*) begin
        if (en)
            y = 1 << a; // Decode input
        else
            y = 8'b00000000; // Outputs are zero when enable is low
    end

endmodule
